import{_ as a,o as t,c as o,a3 as n}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"51. Purchased Leave","description":"","frontmatter":{"title":"51. Purchased Leave","eba":"Mental Health Services 2024-2028","topics":["leave","preliminary"]},"headers":[],"relativePath":"ebas/mental-health/common-terms/leave/51-purchased-leave.md","filePath":"ebas/mental-health/common-terms/leave/51-purchased-leave.md"}'),r={name:"ebas/mental-health/common-terms/leave/51-purchased-leave.md"};function s(l,e,p,h,i,d){return t(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="_51-purchased-leave" tabindex="-1">51. Purchased Leave <a class="header-anchor" href="#_51-purchased-leave" aria-label="Permalink to &quot;51. Purchased Leave&quot;">​</a></h1><p>This clause does not apply to casual Employees.</p><p><strong>51.1</strong> An Employee may, if mutually agreed with the Employer, purchase up to 4 weeks additional paid leave (referred to as Purchased Leave) in a twelve-month period at ordinary pay. The additional paid leave is purchased through salary deductions made over the whole year. The amount deducted will correspond with the amount of leave purchased as per the table below: Purchased Weeks&#39; Proportion of leave additional annual pay paid arrangement leave each week purchased 48/52 4 48/52 49/52 3 49/52 50/52 2 50/52 51/52 1 51/52</p><p>For Example: An Employee who purchased four (4) additional weeks leave would be paid 48/52 or 92.31% of the ordinary rate of pay throughout the relevant 12-month period. If an Employee purchased an additional 2 weeks leave, the Employee would be paid 50/52 or 96.15% of the ordinary rate of pay throughout the relevant 12-month period.</p><p><strong>51.2</strong> All penalties, allowances, loadings or like payments are to be calculated under this Agreement as if the Employee was not participating in the Purchased Leave Arrangement.</p><p><strong>51.3</strong> An Employee participating in a Purchased Leave Arrangement accrues annual leave on the same basis as they would have had they not entered the Purchased Leave Arrangement and is paid leave loading or projected penalties/allowances in respect of such leave in accordance with the terms of the agreement. Purchased Leave does not attract annual leave loading or projected penalties/allowances</p><p><strong>51.4</strong> Purchased Leave may be taken in conjunction with other types of leave.</p><p><strong>51.5</strong> Purchased Leave must be used in the twelve-month period in which it is purchased.</p><p><strong>51.6</strong> The Employer may grant Purchased Leave for a twelve (12) month period, subject to operational requirements. Once approval has been granted, the arrangement may only be varied or cancelled in extraordinary circumstances.</p><p><strong>51.7</strong> Where the:</p><p><strong>(a)</strong> arrangement, has been varied or cancelled because of extraordinary circumstances; or</p><p><strong>(b)</strong> Employee’s employment terminates; or</p><p><strong>(c)</strong> purchased leave has not been taken in the relevant 12-month period the Employer will refund the amount of salary deducted in respect of any unused purchased leave as a lump sum. In the case of variation or cancellation, payment will be made no later than two pay periods following notification of the variation or cancellation.</p><p><strong>51.8</strong> Where the Employee’s employment terminates and the amount of purchased leave taken exceeds the amount deducted, the Employer may deduct, with the consent of the Employee, a sum equal to the negative balance from any remuneration payable to the Employee upon termination of employment.</p><p><strong>51.9</strong> Where the Employee does not consent to the deduction of monies, the Employer and the Employee will agree to a repayment arrangement. The agreement has to be in writing, and has to set out the following:</p><p><strong>(a)</strong> The reason for the repayment</p><p><strong>(b)</strong> The amount of money owed</p><p><strong>(c)</strong> The way repayments will be made</p><p><strong>(d)</strong> How often repayments will be made</p><p>Plain language terms: 48/52, buying leave, extra leave, leave purchase.</p>',20)])])}const u=a(r,[["render",s]]);export{m as __pageData,u as default};
